const HOTMART_LINK = 'https://go.hotmart.com/V83790993U?ap=8c18';

// Countdown starts from a fixed 9m54s (matching the reference image) and counts down
function Countdown() {
  const [total, setTotal] = useState(9 * 60 + 54);

  useEffect(() => {
    const id = setInterval(() => {
      setTotal(prev => (prev > 0 ? prev - 1 : 0));
    }, 1000);
    return () => clearInterval(id);
  }, []);

  const m = String(Math.floor(total / 60)).padStart(2, '0');
  const s = String(total % 60).padStart(2, '0');

  return (
    <span className="font-mono font-bold text-xl text-white tabular-nums">
      {m}:{s}
    </span>
  );
}

